class Solution:
    def maxValue(self, n, index, maxSum):
        def side_cost(slots, peak):
            if peak - 1 >= slots:
                top = peak - 1
                bot = peak - slots
                return (top + bot) * slots // 2
            ones = slots - (peak - 1)
            series = (peak - 1) * peak // 2
            return series + ones
        left = index
        right = n - 1 - index
        lo, hi = 1, maxSum
        ans = 1
        while lo <= hi:
            mid = (lo + hi) // 2
            total = mid + side_cost(left, mid) + side_cost(right, mid)
            if total <= maxSum:
                ans = mid
                lo = mid + 1
            else:
                hi = mid - 1
        return ans

