var maxValue = function(n, index, maxSum) {
    const sideCost = (slots, peak) => {
        if (peak - 1 >= slots) {
            const top = peak - 1;
            const bot = peak - slots;
            return (top + bot) * slots / 2;
        }
        const ones = slots - (peak - 1);
        const series = (peak - 1) * peak / 2;
        return series + ones;
    };
    const left = index;
    const right = n - 1 - index;
    let lo = 1, hi = maxSum, ans = 1;
    while (lo <= hi) {
        const mid = Math.floor((lo + hi) / 2);
        const total = mid + sideCost(left, mid) + sideCost(right, mid);
        if (total <= maxSum) {
            ans = mid;
            lo = mid + 1;
        } else {
            hi = mid - 1;
        }
    }
    return ans;
};
